public class AVLTree {
    public static class Node {
        int val, height;
        Node left, right;
        Node(int d) { val = d; height = 1; }
    }

    // Storage: Helper to query height safely
    private static int height(Node n) { return n == null ? 0 : n.height; }

    // Process: Right Rotation (Single rotation)
    private static Node rightRotate(Node y) {
        Node x = y.left;
        Node T2 = x.right;

        // Perform rotation
        x.right = y;
        y.left = T2;

        // Update heights
        y.height = Math.max(height(y.left), height(y.right)) + 1;
        x.height = Math.max(height(x.left), height(x.right)) + 1;

        return x; // Output: New root reference
    }
}

public class AVLDeletion {
    private static int height(AVLTree.Node n) { return n == null ? 0 : n.height; }
    private static int getBalance(AVLTree.Node n) {
        return n == null ? 0 : height(n.left) - height(n.right);
    }

    public static AVLTree.Node deleteNode(AVLTree.Node root, int key) {
        // Input: root node and key to delete
        if (root == null) return root;

        // Process: Standard BST delete
        if (key < root.val) {
            root.left = deleteNode(root.left, key);
        } else if (key > root.val) {
            root.right = deleteNode(root.right, key);
        } else {
            // Node to delete found
            if ((root.left == null) || (root.right == null)) {
                AVLTree.Node temp = null; // Storage
                if (temp == root.left) temp = root.right;
                else temp = root.left;

                if (temp == null) {
                    temp = root; root = null;
                } else {
                    root = temp; // Copy contents
                }
            } else {
                // Node with two children
                AVLTree.Node temp = minValueNode(root.right); // Storage
                root.val = temp.val;
                root.right = deleteNode(root.right, temp.val);
            }
        }

        if (root == null) return root;

        // Process: Update height
        root.height = Math.max(height(root.left), height(root.right)) + 1;
        int balance = getBalance(root); // Storage

        // rebalancing checks
        // Left Left Case
        if (balance > 1 && getBalance(root.left) >= 0) return rightRotate(root);
        // ... (other rotation cases omitted for space)
        return root; // Output
    }

    private static AVLTree.Node minValueNode(AVLTree.Node node) {
        AVLTree.Node current = node;
        while (current.left != null) current = current.left;
        return current;
    }

    private static AVLTree.Node rightRotate(AVLTree.Node y) {
        AVLTree.Node x = y.left; AVLTree.Node T2 = x.right;
        x.right = y; y.left = T2;
        y.height = Math.max(height(y.left), height(y.right)) + 1;
        x.height = Math.max(height(x.left), height(x.right)) + 1;
        return x;
    }
}

public class AVLGreaterCount {
    public static int countGreater(AVLTree.Node root, int x) {
        // Input: root node and target x

        // Storage: match counter
        int count = 0;
        return helper(root, x);
    }

    private static int helper(AVLTree.Node node, int x) {
        if (node == null) return 0;

        // Process: recursive count accumulation
        int current = (node.val > x) ? 1 : 0; // Storage

        if (node.val > x) {
            // Since node.val > x, all nodes in right subtree are also > x
            return current + helper(node.left, x) + helper(node.right, x);
        } else {
            // node.val <= x, search right subtree only
            return helper(node.right, x);
        }
    }
}

public class AVLMinNodes {
    public static int getMinNodes(int H) {
        // Input: Height H

        // Process: Base cases
        if (H < 0) return 0;
        if (H == 0) return 1; // Output base
        if (H == 1) return 2; // Output base

        // Process: Recurrence evaluation
        int result = getMinNodes(H - 1) + getMinNodes(H - 2) + 1; // Storage

        // Output: return node count
        return result;
    }
}
